import myOpenGL     from '../../myOpenGL.js'

// Hàm đọc file JSON (có thể bỏ vào DialogueAPI hoặc js_glue.js)
const LoadIngredientsDB = async function(_f) {
  try {
    const response = await fetch(`${_f}?t=${Date.now()}`);
    const data = await response.json();
    return data;
  } catch (err) {
    console.error("❌ Lỗi nạp dữ liệu nguyên liệu:", err);
    return [];
  }
};

// 2. Hàm tiện ích để biến URL thành đối tượng Image (HTMLImageElement)
const loadImage = (url) => {
  return new Promise((resolve, reject) => {
    const image = new Image();
    image.src = url;
    image.onload = () => resolve(image);
    image.onerror = (err) => reject(new Error("Không thể tải ảnh tại: " + url));
  });
};

